export interface FplHistory {
  current: {
    event: number;
    points: number;
    total_points: number;
    rank: number;
    rank_sort: number;
    overall_rank: number;
    bank: number;
    value: number;
    points_on_bench: number;
  }[];
}

export interface FplEntry {
  id: number;
  player_first_name: string;
  player_last_name: string;
  player_region_name: string;
  summary_overall_points: number;
  summary_overall_rank: number;
  summary_event_points: number;
  summary_event_rank: number;
  name: string;
}

export interface WrappedData {
  managerName: string;
  teamName: string;
  totalPoints: number;
  overallRank: number;
  bestGameweek: {
    gw: number;
    points: number;
  };
  totalBenchPoints: number;
  worstBenchRegret: {
    gw: number;
    points: number;
  };
  consistencyScore: number;
  aiPersona?: string;
  aiNarration?: string;
}

import { FplEntry, FplHistory, WrappedData } from '../types';

// Use a public CORS proxy because FPL API doesn't allow browser requests
const PROXY_URL = 'https://api.allorigins.win/get?url=';
const FPL_BASE_URL = 'https://fantasy.premierleague.com/api';

export async function fetchFplData(teamId: string): Promise<WrappedData> {
  try {
    const entryUrl = encodeURIComponent(`${FPL_BASE_URL}/entry/${teamId}/`);
    const historyUrl = encodeURIComponent(`${FPL_BASE_URL}/entry/${teamId}/history/`);

    const [entryRes, historyRes] = await Promise.all([
      fetch(`${PROXY_URL}${entryUrl}`),
      fetch(`${PROXY_URL}${historyUrl}`)
    ]);

    const entryDataRaw = await entryRes.json();
    const historyDataRaw = await historyRes.json();

    const entry: FplEntry = JSON.parse(entryDataRaw.contents);
    const history: FplHistory = JSON.parse(historyDataRaw.contents);

    // Calculate Stats
    let maxPoints = 0;
    let bestGW = 1;
    let totalBench = 0;
    let maxBench = 0;
    let maxBenchGW = 1;

    history.current.forEach(gw => {
      if (gw.points > maxPoints) {
        maxPoints = gw.points;
        bestGW = gw.event;
      }
      totalBench += gw.points_on_bench;
      if (gw.points_on_bench > maxBench) {
        maxBench = gw.points_on_bench;
        maxBenchGW = gw.event;
      }
    });

    return {
      managerName: `${entry.player_first_name} ${entry.player_last_name}`,
      teamName: entry.name,
      totalPoints: entry.summary_overall_points,
      overallRank: entry.summary_overall_rank,
      bestGameweek: { gw: bestGW, points: maxPoints },
      totalBenchPoints: totalBench,
      worstBenchRegret: { gw: maxBenchGW, points: maxBench },
      consistencyScore: Math.round((entry.summary_overall_points / history.current.length) * 10) / 10
    };
  } catch (error) {
    console.error("Error fetching FPL data:", error);
    throw new Error("Could not find team data. Please check your Team ID.");
  }
}

