      <div className="relative">
        <div className="text-9xl font-black opacity-10 absolute inset-0 -top-4">OOPS</div>
        <div className="text-8xl font-black text-purple-400">{data.totalBenchPoints}</div>
      </div>
      <p className="text-xl font-bold">Total points left on your bench.</p>
      <div className="glass p-6 rounded-2xl w-full max-w-xs">
        <p className="text-xs uppercase font-bold opacity-50 mb-1">Max Regret</p>
        <p className="text-2xl font-bold">{data.worstBenchRegret.points} pts in GW{data.worstBenchRegret.gw}</p>
