          </div>
        ))}
      </div>

      {/* Controls */}
      <button 
        className="absolute inset-y-0 left-0 w-1/4 z-40 cursor-w-resize" 
        onClick={prevSlide}
        aria-label="Previous Slide"
      />
      <button 
        className="absolute inset-y-0 right-0 w-3/4 z-40 cursor-e-resize" 
        onClick={nextSlide}
        aria-label="Next Slide"
      />

      {/* Navigation Hint */}
      {currentSlide === 0 && (
        <div className="absolute bottom-10 inset-x-0 text-center animate-bounce opacity-50 text-xs font-bold tracking-widest uppercase">
          Tap or Space to continue
        </div>
      )}
    </div>
  );
};

