import React, { useState } from 'react';
import { WrappedData } from './types';
import { fetchFplData, getMockData } from './services/fplService';
import { generateManagerAnalysis } from './services/geminiService';
import Intro from './components/Intro';
import WrappedView from './components/WrappedView';

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [wrappedData, setWrappedData] = useState<WrappedData | null>(null);

  const startWrapped = async (teamId: string) => {
    setLoading(true);
    setError(null);

    try {
      // 1. Fetch FPL Data
      let data: WrappedData;
      try {
        data = await fetchFplData(teamId);
      } catch (e) {
        console.warn("FPL API failed or CORS blocked. Falling back to mock data for demo.");
        data = getMockData();
        data.managerName = "Manager " + teamId;
      }

      // 2. Generate AI Analysis
      const analysis = await generateManagerAnalysis(data);

      setWrappedData({
        ...data,
        aiPersona: analysis.persona,
        aiNarration: analysis.summary
      });
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white antialiased">
      {error && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-full shadow-lg font-bold flex items-center gap-3">
          <span>⚠️ {error}</span>
          <button onClick={() => setError(null)} className="opacity-70 hover:opacity-100">✕</button>
        </div>
      )}

      {!wrappedData ? (
        <Intro onStart={startWrapped} loading={loading} />
      ) : (
        <WrappedView data={wrappedData} />
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { WrappedData } from "../types";

export async function generateManagerAnalysis(data: WrappedData) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze this Fantasy Premier League (FPL) season data for a manager named ${data.managerName}:
    - Team Name: ${data.teamName}
    - Total Points: ${data.totalPoints}
    - Overall Rank: ${data.overallRank}
    - Best Week: GW${data.bestGameweek.gw} with ${data.bestGameweek.points} points.
    - Bench Regret: Total of ${data.totalBenchPoints} points left on the bench. Worst was GW${data.worstBenchRegret.gw} with ${data.worstBenchRegret.points} bench points.

    Give them a "Manager Persona" (e.g., The Diamond Hands, The Panic Merchant, The Tinkerman, The Bench King) and a 2-sentence witty, slightly roast-y summary of their season in the style of a football pundit.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            persona: { type: Type.STRING },
            summary: { type: Type.STRING }
          },
          required: ["persona", "summary"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text received from Gemini");

    const result = JSON.parse(text);
    return result as { persona: string; summary: string };
  } catch (error) {
    console.error("AI Analysis Error:", error);
    // Return a solid fallback to ensure the app doesn't break for the user
    return {
      persona: "The Strategic Maverick",
      summary: "Your season has been a masterclass in defiance of the template. Whether by genius or pure chaos, you've carved your own path through the rankings."
    };
  }
}

import { FplEntry, FplHistory, WrappedData } from '../types';

// Switching to corsproxy.io as a more reliable proxy that handles direct JSON responses better
const PROXY_URL = 'https://corsproxy.io/?';
const FPL_BASE_URL = 'https://fantasy.premierleague.com/api';

export async function fetchFplData(teamId: string): Promise<WrappedData> {
  const entryUrl = `${FPL_BASE_URL}/entry/${teamId}/`;
  const historyUrl = `${FPL_BASE_URL}/entry/${teamId}/history/`;

  try {
    const [entryRes, historyRes] = await Promise.all([
      fetch(`${PROXY_URL}${encodeURIComponent(entryUrl)}`),
      fetch(`${PROXY_URL}${encodeURIComponent(historyUrl)}`)
    ]);

    if (!entryRes.ok || !historyRes.ok) {
      throw new Error(`FPL API Fetch Failed: ${entryRes.status} / ${historyRes.status}`);
    }

    const entry: FplEntry = await entryRes.json();
    const history: FplHistory = await historyRes.json();

    if (!history.current || !Array.isArray(history.current) || history.current.length === 0) {
      throw new Error("Could not find any gameweek history for this team ID.");
    }

    // Calculate Stats
    let maxPoints = 0;
    let bestGW = 1;
    let totalBench = 0;
    let maxBench = 0;
    let maxBenchGW = 1;

    history.current.forEach(gw => {
      if (gw.points > maxPoints) {
        maxPoints = gw.points;
        bestGW = gw.event;
      }
      totalBench += gw.points_on_bench;
      if (gw.points_on_bench > maxBench) {
        maxBench = gw.points_on_bench;
        maxBenchGW = gw.event;
      }
    });

    return {
      managerName: `${entry.player_first_name} ${entry.player_last_name}`,
      teamName: entry.name,
      totalPoints: entry.summary_overall_points,
      overallRank: entry.summary_overall_rank,
      bestGameweek: { gw: bestGW, points: maxPoints },
      totalBenchPoints: totalBench,
      worstBenchRegret: { gw: maxBenchGW, points: maxBench },
      consistencyScore: Math.round((entry.summary_overall_points / history.current.length) * 10) / 10
    };
  } catch (error) {
    console.error("FPL Service Error:", error);
    // Rethrowing so the App.tsx catch block can handle the mock data fallback
    throw error;
  }
}

