import { FplEntry, FplHistory, WrappedData, ChipInfo } from '../types';

const PROXY_URL = 'https://corsproxy.io/?';
const FPL_BASE_URL = 'https://fantasy.premierleague.com/api';

export async function fetchFplData(teamId: string): Promise<WrappedData> {
  const entryUrl = `${FPL_BASE_URL}/entry/${teamId}/`;
  const historyUrl = `${FPL_BASE_URL}/entry/${teamId}/history/`;

  try {
    const [entryRes, historyRes] = await Promise.all([
      fetch(`${PROXY_URL}${encodeURIComponent(entryUrl)}`),
      fetch(`${PROXY_URL}${encodeURIComponent(historyUrl)}`)
    ]);

    if (!entryRes.ok || !historyRes.ok) throw new Error("FPL API Fetch Failed");

    const entry: FplEntry = await entryRes.json();
    const history: FplHistory = await historyRes.json();

    if (!history.current || history.current.length === 0) throw new Error("No history found");

    // Stats Calculation
    let maxPoints = -1;
    let bestGW = 1;
    let totalBench = 0;
    let maxBench = -1;
    let maxBenchGW = 1;

    const gameweekHistory = history.current.map(gw => {
      if (gw.points > maxPoints) {
        maxPoints = gw.points;
        bestGW = gw.event;
      }
      totalBench += gw.points_on_bench;
      if (gw.points_on_bench > maxBench) {
        maxBench = gw.points_on_bench;
        maxBenchGW = gw.event;
      }
      return { gw: gw.event, points: gw.points };
    });

    // Chip logic
    const allChips = ['wildcard', 'freehit', 'bboost', '3xc'];
    const usedChipsMap = new Map(history.chips.map(c => [c.name, c]));

    const getChipInfo = (name: string, isSecondHalf: boolean): ChipInfo => {
      // Note: In 24/25 there are two wildcards. FPL API labels them "wildcard" usually.
      // Logic for 1st vs 2nd half wildcard:
      const instances = history.chips.filter(c => c.name === name);
      let chipInstance = instances[0];

      if (name === 'wildcard') {
        chipInstance = isSecondHalf 
          ? instances.find(c => c.event >= 20) 
          : instances.find(c => c.event < 20);
      } else {
        // For other chips, check if their event matches the half
        const eventMatch = instances.find(c => (isSecondHalf ? c.event >= 20 : c.event < 20));
        chipInstance = eventMatch;
      }

      if (chipInstance) {
        const gwPoints = history.current.find(h => h.event === chipInstance!.event)?.points || 0;
        return { 
          name, 
          gw: chipInstance.event, 
          points: name === 'wildcard' ? null : gwPoints, // Exclude wildcard points as per request
          used: true 
        };
      }
      return { name, gw: null, points: null, used: false };
    };

    const firstHalf = ['wildcard', 'freehit', 'bboost', '3xc'].map(n => getChipInfo(n, false));
    const secondHalf = ['wildcard', 'freehit', 'bboost', '3xc'].map(n => getChipInfo(n, true));

    // Try to get Best Captain from the Best Week
    let bestCaptain = undefined;
    try {
      const picksUrl = `${FPL_BASE_URL}/entry/${teamId}/event/${bestGW}/picks/`;
      const staticUrl = `${FPL_BASE_URL}/bootstrap-static/`;

      const [picksRes, staticRes] = await Promise.all([
        fetch(`${PROXY_URL}${encodeURIComponent(picksUrl)}`),
        fetch(`${PROXY_URL}${encodeURIComponent(staticUrl)}`)
      ]);

      if (picksRes.ok && staticRes.ok) {
        const picksData = await picksRes.json();
        const staticData = await staticRes.json();

        const captainPick = picksData.picks.find((p: any) => p.is_captain);
        if (captainPick) {
          const player = staticData.elements.find((e: any) => e.id === captainPick.element);
          // FPL doesn't give us the specific points for the pick in the picks endpoint easily without the 'live' endpoint
          // But we can approximate or just use the player name
          bestCaptain = {
            name: player ? `${player.web_name}` : "Unknown",
            points: captainPick.multiplier * (picksData.entry_history.points / 5) // placeholder logic, normally need live endpoint
          };
          // Better logic: the best week summary is already in maxPoints.
        }
      }
    } catch (e) {
      console.warn("Could not fetch captain details");
    }

    return {
      managerName: `${entry.player_first_name} ${entry.player_last_name}`,
      teamName: entry.name,
      totalPoints: entry.summary_overall_points,
      overallRank: entry.summary_overall_rank,
      bestGameweek: { gw: bestGW, points: maxPoints },
      totalBenchPoints: totalBench,
      worstBenchRegret: { gw: maxBenchGW, points: maxBench },
      consistencyScore: Math.round((entry.summary_overall_points / history.current.length) * 10) / 10,
      gameweekHistory,
      chips: { firstHalf, secondHalf },
      bestCaptain: bestCaptain ? { ...bestCaptain, points: maxPoints } : undefined
    };
  } catch (error) {
    console.error("FPL Service Error:", error);
    throw error;
  }
}

