import { FplEntry, FplHistory, WrappedData, ChipInfo } from '../types';

const PROXY_URL = 'https://corsproxy.io/?';
const FPL_BASE_URL = 'https://fantasy.premierleague.com/api';

export async function fetchFplData(teamId: string): Promise<WrappedData> {
  const entryUrl = `${FPL_BASE_URL}/entry/${teamId}/`;
  const historyUrl = `${FPL_BASE_URL}/entry/${teamId}/history/`;

  try {
    const [entryRes, historyRes] = await Promise.all([
      fetch(`${PROXY_URL}${encodeURIComponent(entryUrl)}`),
      fetch(`${PROXY_URL}${encodeURIComponent(historyUrl)}`)
    ]);

    if (!entryRes.ok || !historyRes.ok) throw new Error("FPL API Fetch Failed");

    const entry: FplEntry = await entryRes.json();
    const history: FplHistory = await historyRes.json();

    if (!history.current || history.current.length === 0) throw new Error("No history found");

    const staticRes = await fetch(`${PROXY_URL}${encodeURIComponent(`${FPL_BASE_URL}/bootstrap-static/`)}`);
    const staticData = await staticRes.json();

    // Stats Calculation
    let maxPoints = -1;
    let minPoints = Infinity;
    let bestGW = 1;
    let totalBench = 0;
    let maxBench = -1;
    let maxBenchGW = 1;
    let totalPointsSum = 0;
    let totalTransfers = 0;
    let maxTransfersInGW = 0;
    let totalHits = 0;

    const gameweekHistory = history.current.map(gw => {
      if (gw.points > maxPoints) {
        maxPoints = gw.points;
        bestGW = gw.event;
      }
      if (gw.points < minPoints) {
        minPoints = gw.points;
      }
      totalBench += gw.points_on_bench;
      if (gw.points_on_bench > maxBench) {
        maxBench = gw.points_on_bench;
        maxBenchGW = gw.event;
      }
      totalPointsSum += gw.points;
      totalTransfers += gw.event_transfers;
      totalHits += gw.event_transfers_cost;
      if (gw.event_transfers > maxTransfersInGW) {
        maxTransfersInGW = gw.event_transfers;
      }
      return { gw: gw.event, points: gw.points };
    });

    const averagePoints = Math.round(totalPointsSum / history.current.length);

    // Unified Chip logic
    const chips: ChipInfo[] = [];
    const usedChips = history.chips;

    const processChip = async (name: string, displayName: string, event: number | null): Promise<ChipInfo> => {
      if (event === null) {
        return { name, displayName, gw: null, points: null, used: false };
      }
      const gwData = history.current.find(h => h.event === event);
      const gwPoints = gwData?.points || 0;

      let captainName: string | undefined;

      if (name === '3xc') {
        try {
          const picksUrl = `${FPL_BASE_URL}/entry/${teamId}/event/${event}/picks/`;
          const picksRes = await fetch(`${PROXY_URL}${encodeURIComponent(picksUrl)}`);
          if (picksRes.ok) {
            const picksData = await picksRes.json();
            const captainPick = picksData.picks.find((p: any) => p.is_captain);
            if (captainPick) {
              const player = staticData.elements.find((e: any) => e.id === captainPick.element);
              captainName = player?.web_name || "Unknown";
            }
          }
        } catch (e) {
          console.warn("Failed to fetch 3xc picks");
        }
      }

      return {
        name,
        displayName,
        gw: event,
        points: name.includes('wildcard') ? null : gwPoints,
        used: true,
        captainName
      };
    };

    const wc1 = usedChips.find(c => c.name === 'wildcard' && c.event < 20);
    const wc2 = usedChips.find(c => c.name === 'wildcard' && c.event >= 20);
    const fh = usedChips.find(c => c.name === 'freehit');
    const bb = usedChips.find(c => c.name === 'bboost');
    const txc = usedChips.find(c => c.name === '3xc');

    chips.push(await processChip('wildcard', 'Wildcard 1', wc1?.event || null));
    chips.push(await processChip('wildcard', 'Wildcard 2', wc2?.event || null));
    chips.push(await processChip('freehit', 'Free Hit', fh?.event || null));
    chips.push(await processChip('bboost', 'Bench Boost', bb?.event || null));
    chips.push(await processChip('3xc', 'Triple Captain', txc?.event || null));

    let bestCaptain = undefined;
    try {
      const bestPicksUrl = `${FPL_BASE_URL}/entry/${teamId}/event/${bestGW}/picks/`;
      const bestPicksRes = await fetch(`${PROXY_URL}${encodeURIComponent(bestPicksUrl)}`);
      if (bestPicksRes.ok) {
        const picksData = await bestPicksRes.json();
        const captainPick = picksData.picks.find((p: any) => p.is_captain);
        if (captainPick) {
          const player = staticData.elements.find((e: any) => e.id === captainPick.element);
          bestCaptain = {
            name: player?.web_name || "Unknown",
            points: maxPoints
          };
        }
      }
    } catch (e) {
      console.warn("Could not fetch captain details");
    }

    return {
      managerName: `${entry.player_first_name} ${entry.player_last_name}`,
      teamName: entry.name,
      totalPoints: entry.summary_overall_points,
      overallRank: entry.summary_overall_rank,
      bestGameweek: { gw: bestGW, points: maxPoints },
      totalBenchPoints: totalBench,
      worstBenchRegret: { gw: maxBenchGW, points: maxBench },
      consistencyScore: Math.round((entry.summary_overall_points / history.current.length) * 10) / 10,
      averagePoints,
      gameweekHistory,
      chips,
      bestCaptain,
      transferStats: {
        totalTransfers,
        maxTransfersInGW,
        totalHits
      }
    };
  } catch (error) {
    console.error("FPL Service Error:", error);
    throw error;
  }
}

