             <p className="text-xl font-black italic text-green-400 uppercase tracking-tighter leading-tight">"{data.aiPersona}"</p>
          </div>
        </div>
        <div className="bg-white/5 py-4 text-center border-t border-white/5">
          <p className="text-[10px] font-black tracking-[0.5em] opacity-30 uppercase">FPL WRAPPED 24/25</p>
        </div>
      </div>

      <div className="mt-8">
        <button 
          onClick={() => window.location.reload()}
          className="bg-white text-black font-black px-10 py-4 rounded-full transition-all active:scale-95 shadow-2xl uppercase tracking-widest text-sm hover:bg-green-400"
        >
          REWATCH
        </button>
      </div>
    </div>
  ];

  const nextSlide = () => {
    if (currentSlide < slides.length - 1) setCurrentSlide(prev => prev + 1);
  };

  const prevSlide = () => {
    if (currentSlide > 0) setCurrentSlide(prev => prev - 1);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === ' ') nextSlide();
      if (e.key === 'ArrowLeft') prevSlide();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentSlide]);

  return (
    <div className="fixed inset-0 bg-black overflow-hidden select-none touch-none">
      {/* Background Ambience */}
      <div className="absolute inset-0 opacity-20 pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-purple-600 rounded-full blur-[150px] animate-pulse" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-green-500 rounded-full blur-[150px] animate-pulse" style={{ animationDelay: '1s' }} />
      </div>

      {/* Progress Bars */}
      <div className="absolute top-6 inset-x-6 flex gap-1.5 z-50">
        {slides.map((_, i) => (
          <div key={i} className="h-1 flex-1 bg-white/20 rounded-full overflow-hidden">
            <div 
              className={`h-full bg-white transition-all duration-300 ${i <= currentSlide ? 'opacity-100' : 'opacity-0'}`}
              style={{ width: i === currentSlide ? '100%' : i < currentSlide ? '100%' : '0%' }}
            />
          </div>
        ))}
      </div>

      {/* Slide Transition Layer */}
      <div className="h-full relative overflow-hidden">
        {slides.map((slide, i) => (
          <div 
            key={i} 
            className={`absolute inset-0 h-full w-full transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] ${
              i === currentSlide 
                ? 'opacity-100 scale-100 translate-y-0 pointer-events-auto' 
                : i < currentSlide 
                  ? 'opacity-0 scale-90 -translate-y-20 pointer-events-none' 
                  : 'opacity-0 scale-110 translate-y-20 pointer-events-none'
            }`}
          >
            {slide}
          </div>
        ))}
      </div>

      {/* Navigation Areas */}
      <div className="absolute inset-0 flex z-40">
        <div className="w-1/3 h-full cursor-w-resize" onClick={prevSlide} />
        <div className="w-2/3 h-full cursor-e-resize" onClick={nextSlide} />
      </div>

      {/* Scroll Hint */}
      {currentSlide === 0 && (
        <div className="absolute bottom-12 inset-x-0 flex flex-col items-center gap-2 pointer-events-none opacity-40">
          <div className="w-6 h-10 border-2 border-white rounded-full flex justify-center p-1">
             <div className="w-1.5 h-1.5 bg-white rounded-full animate-bounce" />
          </div>
          <p className="text-[10px] font-black tracking-widest uppercase">Start Experience</p>
        </div>
      )}
    </div>
  );
};

