import { GoogleGenAI, Type } from "@google/genai";
import { WrappedData } from "../types";

export async function generateManagerAnalysis(data: WrappedData) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze this Fantasy Premier League (FPL) season for manager ${data.managerName}:
    - Total Points: ${data.totalPoints} (Rank: ${data.overallRank})
    - Knee-Jerk Score: ${data.transferStats.kneeJerkScore}% (Percentage of transfers made immediately after deadlines).
    - Template vs Maverick: ${data.metrics.templateScore}% template.
    - Bench Pain: ${data.totalBenchPoints} points wasted on bench.
    - Loyalty: Their most loyal player was ${data.loyaltyList[0]?.name}.
    - Hindsight: They could have scored ${data.metrics.hindsightTotal} if they were perfect.

    Give them a funny "Manager Persona" (e.g., "The Hindsight Specialist", "The Impulse Buyer", "The Template Slave", "The Chaos Merchant") and a 2-sentence witty, roast-y summary. 
    Be direct, using football pundit slang (e.g. "proper 'cheer up' manager", "absolute scenes").
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            persona: { type: Type.STRING },
            summary: { type: Type.STRING }
          },
          required: ["persona", "summary"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text");
    return JSON.parse(text) as { persona: string; summary: string };
  } catch (error) {
    return {
      persona: "The Strategic Maverick",
      summary: "Your season has been a masterclass in defiance of the template. Whether by genius or pure chaos, you've carved your own path."
    };
  }
}

