                  <p className="text-2xl font-black text-red-500">{data.transferStats.kneeJerkScore}%</p>
               </div>
               <div className="space-y-0.5">
                  <p className="text-[8px] font-bold opacity-30 uppercase tracking-widest">BEST MOMENT</p>
                  <p className="text-xs font-black text-cyan-400 leading-tight uppercase">{data.metrics.bestMoment}</p>
               </div>
